#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K, Q;
        scanf("%d %d %d", &N, &K, &Q);
        int a, b, c, d, e, f, r, s, t, m, A1;
        scanf("%d %d %d %d %d %d %d %d %d %d %d", &a, &b, &c, &d, &e, &f, &r, &s, &t, &m, &A1);
        int L1, La, Lc, Lm, D1, Da, Dc, Dm;
        scanf("%d %d %d %d %d %d %d %d", &L1, &La, &Lc, &Lm, &D1, &Da, &Dc, &Dm);
        int A[N + 1];
        A[1] = A1;
        for (int i = 2; i <= N; i++) {
            if ((t * i) % s <= r) {
                A[i] = (a * A[i - 1] * A[i - 1] + b * A[i - 1] + c) % m;
            } else {
                A[i] = (d * A[i - 1] * A[i - 1] + e * A[i - 1] + f) % m;
            }
        }
        long long sum = 0;
        long long product = 1;
        for (int i = 0; i < Q; i++) {
            L1 = (La * L1 + Lc) % Lm;
            D1 = (Da * D1 + Dc) % Dm;
            int L = L1 + 1;
            int R = (L + K - 1 + D1) < N ? L + K - 1 + D1 : N;
            int min_taste = A[L];
            for (int j = L + 1; j <= R; j++) {
                if (A[j] < min_taste) {
                    min_taste = A[j];
                }
            }
            sum += min_taste;
            product = (product * min_taste) % MOD;
        }
        printf("%lld %lld\n", sum, product);
    }
    return 0;
}

